create table admin (created_at_user timestamp(6), id bigint generated by default as identity, role_user varchar(255) check ((role_user in ('ADMIN','ALUNO','PROFESSOR','COORDENADOR'))), user_email varchar(255), user_name varchar(255), primary key (id));
create table buy (buy_created_at date, buy_quantity integer, buy_aluno_id bigint unique, buy_id bigint generated by default as identity, buy_professor_id bigint unique, buy_class_group varchar(255), buy_equipment varchar(255), buy_mechanical_set varchar(255), buy_patrimony varchar(255), buy_purchase_justification varchar(255), buy_sap varchar(255), buy_status varchar(255) check ((buy_status in ('Entregue','EmAnalise','Pedideemandamento','Naovisualizado'))), buy_tag varchar(255), buy_technical_specification varchar(255), primary key (buy_id));
create table buy_media_files (buy_id bigint not null, media_file varchar(255));
create table class (created_at_user timestamp(6), id bigint generated by default as identity, acronym_class varchar(255), role_user varchar(255) check ((role_user in ('ADMIN','ALUNO','PROFESSOR','COORDENADOR'))), user_email varchar(255), user_name varchar(255), primary key (id));
create table class_students (class_id bigint not null, students_id bigint not null);
create table class_teachers (classes_id bigint not null, teachers_id bigint not null);
create table coordinator (created_at_user timestamp(6), id bigint generated by default as identity, role_user varchar(255) check ((role_user in ('ADMIN','ALUNO','PROFESSOR','COORDENADOR'))), user_email varchar(255), user_name varchar(255), primary key (id));
create table designation (designation_id bigint generated by default as identity, designation_sector varchar(255) check ((designation_sector in ('AREA_NAO_DESIGNADA','CENTRO_WEG','WEG_MANUTENCAO'))), primary key (designation_id));
create table equipment (equipement_price numeric(38,2), equipement_quantity integer, equipment_id bigint generated by default as identity, equipement_sap varchar(255), equipment_name varchar(255), primary key (equipment_id));
create table helper_material (helper_material_id bigint generated by default as identity, helper_material_link_lubrification varchar(255), helper_material_link_manual varchar(255), helper_material_link_prevent_maintance varchar(255), helper_material_link_tecnic varchar(255), primary key (helper_material_id));
create table machine (machine_created_at timestamp(6), machine_id bigint generated by default as identity, machine_place_id bigint, machine_heritage varchar(255), machine_name varchar(255), primary key (machine_id));
create table machine_log (machine_log_conclusion timestamp(6), machine_log_hour_register timestamp(6), machine_log_id bigint generated by default as identity, machine_log_machine_id bigint, machine_log_responsible_id bigint, machine_log_description varchar(255), machine_log_service_execute varchar(255), machine_log_title varchar(255), primary key (machine_log_id));
create table place (place_id bigint generated by default as identity, place_name varchar(255), primary key (place_id));
create table student (created_at_user timestamp(6), id bigint generated by default as identity, role_user varchar(255) check ((role_user in ('ADMIN','ALUNO','PROFESSOR','COORDENADOR'))), user_email varchar(255), user_name varchar(255), primary key (id));
create table teacher (created_at_user timestamp(6), id bigint generated by default as identity, role_user varchar(255) check ((role_user in ('ADMIN','ALUNO','PROFESSOR','COORDENADOR'))), user_email varchar(255), user_name varchar(255), primary key (id));

alter table buy add constraint fk_buy_student foreign key (buy_aluno_id) references student;
alter table buy add constraint fk_buy_teacher foreign key (buy_professor_id) references teacher;
alter table buy_media_files add constraint fk_buy_media_files_buy foreign key (buy_id) references buy;
alter table class_students add constraint fk_class_students_student foreign key (students_id) references student;
alter table class_students add constraint fk_class_students_class foreign key (class_id) references class;
alter table class_teachers add constraint fk_class_teachers_teacher foreign key (teachers_id) references teacher;
alter table class_teachers add constraint fk_class_teachers_class foreign key (classes_id) references class;
alter table machine add constraint fk_machine_place foreign key (machine_place_id) references place;
alter table machine_log add constraint fk_machine_log_machine foreign key (machine_log_machine_id) references machine;
alter table machine_log add constraint fk_machine_log_teacher foreign key (machine_log_responsible_id) references teacher;
